def calculate_tax(order_record):
    total_cost = sum(item.price * item.quantity for item in order_record.cart_items)
    if order_record.discount_code:
        total_cost -= Discount(order_record.discount_code, "", 0).amount
    tax_amount = total_cost * order_record.tax_rate
    return total_cost + tax_amount

